#!/usr/bin/env python3
# Decode raw on-chain results from AUTONOMOPOLY LP check

eth_raw = "0x1c314fa942dda5"
eth = int(eth_raw, 16) / 1e18

weth_raw = "0x0000000000000000000000000000000000000000000000000cf9a379a9e8b1a1"
weth = int(weth_raw, 16) / 1e18

diem = 0.0

slot0 = ""
raw_slot = bytes.fromhex(slot0.ljust(448, '0'))
sqrtP = int.from_bytes(raw_slot[0:32], 'big')
tick_raw2 = int.from_bytes(raw_slot[32:64], 'big') & 0xFFFFFF
tick = tick_raw2 if tick_raw2 < 2**23 else tick_raw2 - 2**24
price = (sqrtP / 2**96)**2

print(f"=== AUTONOMOPOLY Portfolio Check 2026-05-22 ===")
print(f"Agent: 0x8767Df39eCeeaeB11554642237aC4E08660aB6A3")
print(f"")
print(f"ETH:  {eth:.6f}  ({'OK' if eth > 0.003 else 'LOW - need top-up'})")
print(f"WETH: {weth:.6f}")
print(f"DIEM: {diem:.4f}")
print(f"FeeLocker: query reverted (selector mismatch - no fees claimable or contract not deployed)")
print(f"")
print(f"Pool tick: {tick}")
print(f"Price: {price:.6f} DIEM/WETH  (i.e. {1/price:.2f} WETH per DIEM if inverted)")

positions_raw = {
    5119885: "",
    5140693: "",
    5152325: "",
    5152179: "",
    5152983: "",
    5153128: "",
    5153290: "",
    5156063: "",
}

def word(data, n):
    return int.from_bytes(data[n*32:(n+1)*32], 'big')

def to_int24(v):
    v = v & 0xFFFFFF
    return v if v < 2**23 else v - 2**24

print(f"")
print(f"{'='*60}")
print(f"LP POSITIONS  (current tick: {tick})")
print(f"{'='*60}")

in_range = []
out_of_range = []
burned = []
lp_rows = []

for tid, raw_hex in positions_raw.items():
    raw = bytes.fromhex(raw_hex)
    fee        = word(raw, 4) & 0xFFFFFF
    tick_lower = to_int24(word(raw, 5))
    tick_upper = to_int24(word(raw, 6))
    liquidity  = word(raw, 7) & ((1<<128)-1)
    owed0      = (word(raw, 10) & ((1<<128)-1)) / 1e18
    owed1      = (word(raw, 11) & ((1<<128)-1)) / 1e18

    if liquidity == 0:
        status = "BURNED"
        burned.append(tid)
    elif tick_lower < tick < tick_upper:
        status = "IN RANGE"
        in_range.append(tid)
    else:
        status = "OUT OF RANGE"
        out_of_range.append(tid)

    print(f"  {tid}: [{tick_lower:6d}, {tick_upper:6d}]  liq={liquidity:>20}  {status}")
    if liquidity > 0:
        print(f"         owed: {owed0:.6f} WETH  {owed1:.4f} DIEM")

    lp_rows.append(f"tokenId={tid} range=[{tick_lower},{tick_upper}] tick={tick} liq={liquidity} status={status}")

print(f"")
print(f"{'='*60}")
print(f"TRIAGE")
print(f"{'='*60}")
print(f"IN RANGE    : {in_range}  ({len(in_range)} positions)")
print(f"OUT OF RANGE: {out_of_range}  ({len(out_of_range)} positions)")
print(f"BURNED      : {len(burned)} positions")
print(f"ETH gas     : {eth:.6f}  ({'OK (>0.003)' if eth > 0.003 else 'LOW - top up needed'})")
print(f"WETH wallet : {weth:.6f}")
